You can use this cloud function to manage articles. Here's sample code for calling it in a mini program: 

```js
// Create
wx.cloud.callFunction({
  name: 'post-management',
  data: {
    action: 'createPost',
    data: {
      title: 'My 1st Article',
      content: 'this is the content',
      author: 'David',
    }
  }
}).then(res => {
  console.log('Create result: ', res)
})

// response example
{
  "id": "64c9f5a79f6c8e0001b60b0a",
  "requestId": "1735086147_0.36272387876657_33594-193f355e_1"
}

// Update
wx.cloud.callFunction({
  name: 'post-management',
  data: {
    action: 'updatePost',
    data: {
      id: '64c9f5a79f6c8e0001b60b0a',
      post: {
        content: 'Update content'
      }
    }
  }
}).then(res => {
  console.log('Update result: ', res)
})

// response example
{
  "id": "64c9f5a79f6c8e0001b60b0a",
  "updated": 1
}

// Delete
wx.cloud.callFunction({
  name: 'post-management',
  data: {
    action: 'deletePost',
    data: {
      id: '64c9f5a79f6c8e0001b60b0a'
    }
  }
}).then(res => {
  console.log('Delete result: ', res)
})

// response example
{
  "requestId": "1735086147_0.36272387876657_33594-193f355e_1",
  "deleted": 1
}

// Get One
wx.cloud.callFunction({
  name: 'post-management',
  data: {
    action: 'getPost',
    data: {
      id: '64c9f5a79f6c8e0001b60b0a'
    }
  }
}).then(res => {
  console.log('Get one: ', res)
})

// response example
{
  "data": [
    {
      "_id": "64c9f5a79f6c8e0001b60b0a",
      "title": "My 1st Article",
      "content": "this is the content",
      "author": "David"
      // ...
    }
  ],
  "requestId": "1735086147_0.36272387876657_33594-193f355e_1"
}

// Pagination
wx.cloud.callFunction({
  name: 'post-management',
  data: {
    action: 'listPosts',
    data: {
      page: 1,
      pageSize: 10
    }
  }
}).then(res => {
  console.log('Pagination result: ', res)
})

// response
{
  "list": [
    {
      "_id": "64c9f5a79f6c8e0001b60b0a",
      "title": "1st Article",
      "content": "update content",
      "author": "David"
      // ...
    }
    // ... more
  ],
  "total": 100,
  "page": 1,
  "pageSize": 10
}

// Search
wx.cloud.callFunction({
  name: 'post-management',
  data: {
    action: 'searchPosts',
    data: {
      keyword: 'tech'
    }
  }
}).then(res => {
  console.log('Search: ', res)
})

// response
{
  "data": [
    {
      "_id": "64c9f5a79f6c8e0001b60b0a",
      "title": "1st Article",
      "content": "update content",
      "author": "David"
      // ...
    }
    // more
  ],
  "requestId": "1735086147_0.36272387876657_33594-193f355e_1"
}
```
